import{_ as a,c as t,a7 as l,o as e}from"./chunks/framework.Bfq_PhNx.js";const c=JSON.parse('{"title":"DV-01-Introduction","description":"","frontmatter":{"date":"2025-12-30T00:00:00.000Z","title":"DV-01-Introduction","status":"DONE","author":["AllenYGY"],"tags":["NOTE","DataVisualization"],"publish":true,"slidev":false},"headers":[],"relativePath":"posts/Data Analysis/Data Visualization/DV-01-Introduction.md","filePath":"posts/Data Analysis/Data Visualization/DV-01-Introduction.md","lastUpdated":null}'),s={name:"posts/Data Analysis/Data Visualization/DV-01-Introduction.md"};function o(n,i,r,h,d,u){return e(),t("div",null,[...i[0]||(i[0]=[l('<ul><li><strong>什么是数据可视化？</strong></li><li><strong>为什么要做数据可视化？</strong></li><li><strong>数据可视化的理论模型与语言</strong></li><li><strong>数据可视化的发展历史与分支</strong></li></ul><hr><h1 id="dv-01-introduction" tabindex="-1">DV-01-Introduction <a class="header-anchor" href="#dv-01-introduction" aria-label="Permalink to &quot;DV-01-Introduction&quot;">​</a></h1><ul><li>What is data visualization？ <ul><li>The use of computer-supported, interactive, visual representations of data to amplify cognition.</li></ul></li><li>Why do we need data visualization？ <ul><li>Data visualization tools are key to ‘big data’ analysis</li><li>One picture is worth ten thousand words</li><li>Statistics may mislead the users</li><li>Optical illusion: Use color, light and patterns to create images that can be deceptive or misleading to our brains.</li><li>Reading a picture is faster to grasp the information than reading the text for humans. So we need to study the human perception system and learn how to design a good visualization.</li></ul></li></ul><hr><h2 id="dv-theory-model" tabindex="-1">DV Theory Model <a class="header-anchor" href="#dv-theory-model" aria-label="Permalink to &quot;DV Theory Model&quot;">​</a></h2><h3 id="dikw-模型-概念-理解" tabindex="-1">DIKW 模型（概念 + 理解） <a class="header-anchor" href="#dikw-模型-概念-理解" aria-label="Permalink to &quot;DIKW 模型（概念 + 理解）&quot;">​</a></h3><p><strong>Data → Information → Knowledge → Wisdom</strong>（Ackoff, 1989）</p><p>你需要会：</p><ul><li>每一层是什么意思</li><li>数据可视化主要解决哪一层（👉 Information / Knowledge）</li></ul><hr><h3 id="数据可视化的模型-重点中的重点" tabindex="-1">数据可视化的模型（重点中的重点） <a class="header-anchor" href="#数据可视化的模型-重点中的重点" aria-label="Permalink to &quot;数据可视化的模型（重点中的重点）&quot;">​</a></h3><h4 id="van-wijk-的-visualization-model-2005" tabindex="-1">van Wijk 的 Visualization Model（2005） <a class="header-anchor" href="#van-wijk-的-visualization-model-2005" aria-label="Permalink to &quot;van Wijk 的 Visualization Model（2005）&quot;">​</a></h4><p>要点：</p><ul><li><strong>对象（Squares）</strong>：D（data）, S（specification）, I（image）, K（knowledge）</li><li><strong>行为（Circles）</strong>：V（visualize）, P（perceive）, E（explore）</li></ul><p>👉 考法：</p><ul><li>图中某个字母代表什么</li><li>“perceive”和“explore”有什么不同</li></ul><hr><h4 id="information-visualization-reference-model-card-et-al" tabindex="-1">Information Visualization Reference Model（Card et al.） <a class="header-anchor" href="#information-visualization-reference-model-card-et-al" aria-label="Permalink to &quot;Information Visualization Reference Model（Card et al.）&quot;">​</a></h4><p>流程要能说清：</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Raw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Data</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> →</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Data</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Tables</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> →</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Visual</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Structures</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> →</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Views</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> →</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Human</span></span></code></pre></div><p>中间有：</p><ul><li>transformations</li><li>visual mapping</li><li>interaction</li></ul><hr><h3 id="grammar-of-graphics" tabindex="-1">Grammar of Graphics <a class="header-anchor" href="#grammar-of-graphics" aria-label="Permalink to &quot;Grammar of Graphics&quot;">​</a></h3><p>核心作者与时间线（会考配对）：</p><ul><li>Wilkinson（1999）：Grammar of Graphics</li><li>Wickham（2005）：ggplot2</li><li>Wickham（2010）：Layered Grammar of Graphics</li></ul><p>核心元素：</p><ul><li>Data</li><li>Geometry</li><li>Scale</li><li>Aesthetics</li><li>Coordinates</li><li>Facets</li></ul><hr><h2 id="三、历史部分怎么复习最省力-不死背" tabindex="-1">三、历史部分怎么复习最省力（不死背） <a class="header-anchor" href="#三、历史部分怎么复习最省力-不死背" aria-label="Permalink to &quot;三、历史部分怎么复习最省力（不死背）&quot;">​</a></h2><p>记住 <strong>“人 + 技术 + 目的”</strong> 三件事即可。</p><h3 id="关键人物-必认" tabindex="-1">关键人物（必认） <a class="header-anchor" href="#关键人物-必认" aria-label="Permalink to &quot;关键人物（必认）&quot;">​</a></h3><ul><li><strong>William Playfair</strong>：折线图、柱状图、饼图</li><li><strong>Florence Nightingale</strong>：玫瑰图（说服）</li><li><strong>John Snow</strong>：霍乱地图（分析）</li><li><strong>Charles Minard</strong>：拿破仑远征（多维信息）</li><li><strong>John Tukey</strong>：EDA（探索性数据分析）</li><li><strong>Jacques Bertin</strong>：视觉变量理论</li></ul><p>👉 考法：</p><p>“Who used visualization to persuade?” “Which visualization supports hypothesis generation?”</p><hr><h2 id="四、三大分支-几乎必考" tabindex="-1">四、三大分支（几乎必考） <a class="header-anchor" href="#四、三大分支-几乎必考" aria-label="Permalink to &quot;四、三大分支（几乎必考）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>分支</th><th>数据类型</th><th>关键词</th></tr></thead><tbody><tr><td>SciVis</td><td>空间数据</td><td>volume, flow</td></tr><tr><td>InfoVis</td><td>抽象数据</td><td>network, hierarchy</td></tr><tr><td>Visual Analytics</td><td>分析推理</td><td>human + machine</td></tr></tbody></table><p>一句话记忆法：</p><blockquote><p><strong>SciVis 看空间，InfoVis 看结构，VA 看推理</strong></p></blockquote><hr>',42)])])}const g=a(s,[["render",o]]);export{c as __pageData,g as default};
